ShellRoute(
  builder: (context, state, child) {
    return ScaffoldWithNavBar(child: child);
  },
  routes: [
    GoRoute(path: '/movies', builder: (context, state) => MoviesScreen()),
    GoRoute(path: '/favorites', builder: (context, state) => FavoritesScreen()),
  ],
)

class ScaffoldWithNavBar extends StatelessWidget {
  final Widget child;
  const ScaffoldWithNavBar({required this.child});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: child,
      bottomNavigationBar: BottomNavigationBar(...),
    );
  }
}

ShellRoute(
  builder: (context, state, child) => ScaffoldWithNavBar(child: child),
  routes: [
    GoRoute(
      path: '/movies',
      builder: (context, state) => MoviesScreen(),
      routes: [
        GoRoute(path: 'details/:id', builder: (context, state) => MovieDetailsScreen()),
      ],
    ),
  ],
)
